#include <iostream>
using namespace std;

int main() {
    int marks = 85;

    if (marks >= 90) {
        cout << "Grade A" << endl;
    } else if (marks >= 75) {
        cout << "Grade B" << endl;
    } else if (marks >= 60) {
        cout << "Grade C" << endl;
    } else if (marks >= 40) {
        cout << "Grade D" << endl;
    } else {
        cout << "Fail" << endl;
    }

    // Another example: temperature
    int temp = 30;
    if (temp > 35) {
        cout << "Hot" << endl;
    } else if (temp > 20) {
        cout << "Warm" << endl;
    } else if (temp > 10) {
        cout << "Cool" << endl;
    } else {
        cout << "Cold" << endl;
    }

    return 0;
}

#include <iostream>
using namespace std;

int main() {
    int age = 25;
    bool hasLicense = true;

    if (age >= 18) {
        cout << "You are old enough." << endl;
        if (hasLicense) {
            cout << "You can drive." << endl;
        } else {
            cout << "You need a license to drive." << endl;
        }
    } else {
        cout << "You are too young to drive." << endl;
    }

    // Find largest of three numbers
    int a = 10, b = 25, c = 15;
    int largest;
    if (a > b) {
        if (a > c) largest = a;
        else largest = c;
    } else {
        if (b > c) largest = b;
        else largest = c;
    }
    cout << "Largest of " << a << ", " << b << ", " << c << " is " << largest << endl;

    return 0;
}

#include <iostream>
using namespace std;

int main() {
    char grade = 'B';

    switch (grade) {
        case 'A':
            cout << "Excellent!" << endl;
            break;
        case 'B':
            cout << "Good job!" << endl;
            break;
        case 'C':
            cout << "Fair" << endl;
            break;
        case 'D':
            cout << "Needs improvement" << endl;
            break;
        default:
            cout << "Invalid grade" << endl;
    }

    // Fall-through example (intentionally)
    int day = 3;
    switch (day) {
        case 1:
        case 2:
        case 3:
        case 4:
        case 5:
            cout << "Weekday" << endl;
            break;
        case 6:
        case 7:
            cout << "Weekend" << endl;
            break;
        default:
            cout << "Invalid day" << endl;
    }

    return 0;
}

#include <iostream>
using namespace std;

int main() {
    // Basic counting up
    cout << "Counting up: ";
    for (int i = 1; i <= 5; i++) {
        cout << i << " ";
    }
    cout << endl;

    // Counting down
    cout << "Counting down: ";
    for (int i = 10; i >= 1; i--) {
        cout << i << " ";
    }
    cout << endl;

    // Step by 2 (even numbers)
    cout << "Even numbers: ";
    for (int i = 2; i <= 10; i += 2) {
        cout << i << " ";
    }
    cout << endl;

    // Sum of first 10 numbers
    int sum = 0;
    for (int i = 1; i <= 10; i++) {
        sum += i;
    }
    cout << "Sum 1 to 10 = " << sum << endl;

    // Multiple variables
    for (int i = 0, j = 10; i < j; i++, j--) {
        cout << "i=" << i << ", j=" << j << endl;
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
using namespace std;

int main() {
    // Array
    int numbers[] = {10, 20, 30, 40, 50};
    cout << "Array: ";
    for (int n : numbers) {
        cout << n << " ";
    }
    cout << endl;

    // Vector
    vector<double> prices = {1.99, 2.49, 3.79};
    cout << "Prices: ";
    for (double p : prices) {
        cout << p << " ";
    }
    cout << endl;

    // String
    string word = "Hello";
    cout << "Characters: ";
    for (char c : word) {
        cout << c << " ";
    }
    cout << endl;

    // Modify elements (use reference &)
    for (int& n : numbers) {
        n *= 2;
    }
    cout << "Doubled array: ";
    for (int n : numbers) {
        cout << n << " ";
    }
    cout << endl;

    return 0;
}

#include <iostream>
using namespace std;

int main() {
    // Print 1 to 5
    int i = 1;
    while (i <= 5) {
        cout << i << " ";
        i++;
    }
    cout << endl;

    // Sum digits of a number
    int num = 12345;
    int sum = 0;
    while (num > 0) {
        sum += num % 10;
        num /= 10;
    }
    cout << "Sum of digits = " << sum << endl;

    // Keep reading until valid input
    int input;
    cout << "Enter a positive number: ";
    cin >> input;
    while (input <= 0) {
        cout << "Invalid. Try again: ";
        cin >> input;
    }
    cout << "You entered " << input << endl;

    return 0;
}

#include <iostream>
using namespace std;

int main() {
    // Runs at least once even if condition false
    int x = 10;
    do {
        cout << "This runs once: x = " << x << endl;
    } while (x < 5);

    // Menu system
    int choice;
    do {
        cout << "\n--- MENU ---" << endl;
        cout << "1. Say Hello" << endl;
        cout << "2. Say Goodbye" << endl;
        cout << "3. Exit" << endl;
        cout << "Choice: ";
        cin >> choice;

        switch (choice) {
            case 1:
                cout << "Hello!" << endl;
                break;
            case 2:
                cout << "Goodbye!" << endl;
                break;
            case 3:
                cout << "Exiting..." << endl;
                break;
            default:
                cout << "Invalid choice" << endl;
        }
    } while (choice != 3);

    return 0;
}

#include <iostream>
using namespace std;

int main() {
    // Stop loop when i equals 5
    for (int i = 1; i <= 10; i++) {
        if (i == 5) {
            cout << "Breaking at " << i << endl;
            break;
        }
        cout << i << " ";
    }
    cout << endl;

    // Find first even number in array
    int arr[] = {3, 7, 9, 12, 15};
    int found = -1;
    for (int i = 0; i < 5; i++) {
        if (arr[i] % 2 == 0) {
            found = arr[i];
            break;
        }
    }
    cout << "First even number: " << found << endl;

    return 0;
}

#include <iostream>
using namespace std;

int main() {
    // Print only odd numbers
    cout << "Odd numbers: ";
    for (int i = 1; i <= 10; i++) {
        if (i % 2 == 0) continue;
        cout << i << " ";
    }
    cout << endl;

    // Skip vowels
    string text = "Hello World";
    string vowels = "aeiouAEIOU";
    cout << "Consonants only: ";
    for (char c : text) {
        bool isVowel = false;
        for (char v : vowels) {
            if (c == v) {
                isVowel = true;
                break;
            }
        }
        if (isVowel) continue;
        cout << c;
    }
    cout << endl;

    return 0;
}

#include <iostream>
using namespace std;

int main() {
    int num = 1;

    start:
    cout << num << " ";
    num++;
    if (num <= 5) goto start;
    cout << endl;

    // Nested loops break out easily with goto
    for (int i = 0; i < 5; i++) {
        for (int j = 0; j < 5; j++) {
            if (i == 2 && j == 3) {
                goto exit_loops;
            }
            cout << "(" << i << "," << j << ") ";
        }
        cout << endl;
    }
    exit_loops:
    cout << "\nExited loops at i=2, j=3" << endl;

    return 0;
}

#include <iostream>
using namespace std;

int main() {
    // Multiplication table (10x10)
    cout << "Multiplication Table:\n";
    for (int i = 1; i <= 10; i++) {
        for (int j = 1; j <= 10; j++) {
            cout << i * j << "\t";
        }
        cout << endl;
    }

    // Triangle pattern
    int rows = 5;
    cout << "\nTriangle pattern:\n";
    for (int i = 1; i <= rows; i++) {
        for (int j = 1; j <= i; j++) {
            cout << "* ";
        }
        cout << endl;
    }

    // Prime numbers up to 50
    cout << "\nPrime numbers up to 50: ";
    for (int n = 2; n <= 50; n++) {
        bool isPrime = true;
        for (int d = 2; d * d <= n; d++) {
            if (n % d == 0) {
                isPrime = false;
                break;
            }
        }
        if (isPrime) cout << n << " ";
    }
    cout << endl;

    return 0;
}
